// legacy_onboarding is already credential-free (logins were stripped at export).
// This is a defense-in-depth net: drop any field whose label looks like a login.
const CRED = /password|username\s*&\s*password|back ?up code|login details|apple id/i;
const rows = $input.all().map(i => i.json);
const subs = rows.filter(r => r && r.id).map(r => {
  const fields = (Array.isArray(r.fields) ? r.fields : []).filter(f => f && !CRED.test(String(f.label || '')));
  return { id: r.id, slug: r.slug || '', first_name: r.first_name || '', last_name: r.last_name || '', email: r.email || '', phone: r.phone || '', submitted_on: r.submitted_on || '', created_at: r.created_at || '', fields };
});
return [{ json: { ok: true, count: subs.length, submissions: subs } }];
